
function fixed(){var $header=document.querySelector(".site-header");window.addEventListener("scroll",function(e){if(window.scrollY||window.pageYOffset||document.body.scrollTop+((document.documentElement&&document.documentElement.scrollTop)||0)){$header.classList.add("fixed")}else{$header.classList.remove("fixed")}})}
function modal(){var modals=document.querySelectorAll(".js-open-modal");for(var i=modals.length-1;i>=0;i--){var $modalLink=modals[i];var $open="."+$modalLink.getAttribute("data-open");var $modal=document.querySelector($open);var $closeBtn=$modal.querySelector(".close");$modalLink.addEventListener("click",function(event){event.preventDefault();$modal.classList.add("visible")});$closeBtn.addEventListener("click",function(){$modal.classList.remove("visible")})}}
function visible(){var $title=document.querySelector(".home__header-title .primary.hidden");var $title2=document.querySelector(".home__header-title .black.hidden");var $blocs=document.querySelectorAll(".home__header-blocs__item");var $hidden=document.querySelectorAll(".hidden");if($hidden){for(var j=0,length2=$hidden.length;j<length2;j++){$hidden[j].classList.add("visible")}}
if($title){$title.classList.add("visible");$title2.classList.add("visible")}
for(var j=0,length2=$blocs.length;j<length2;j++){$blocs[j].classList.add("visible")}}
function openMenu(){var $menu=document.querySelector(".burger");var $open=document.querySelector(".navigation");var $close=document.querySelector(".navigation .close");$menu.addEventListener("click",function(){$open.classList.add("active")});$open.addEventListener("click",function(){$open.classList.remove("active")});$close.addEventListener("click",function(){$open.classList.remove("active")})}
function openMission(){var timeInMs=Date.now();var $missions=document.querySelectorAll(".home__mission-item__discover");for(var i=$missions.length-1;i>=0;i--){var $missionsLink=$missions[i];var $open="."+$missionsLink.getAttribute("data-id");$missionsLink.addEventListener("click",function(){console.log("click");jQuery.post(ajaxurl,{action:"loadMissions",date:timeInMs,id:$open,},function(data){console.log(data)})})}}
function accordion(){var $accordion=document.querySelectorAll(".accordion");for(var i=$accordion.length-1;i>=0;i--){var currentAccordion=$accordion[i];var $items=currentAccordion.querySelectorAll(".accordion-wrapper");for(var j=0,length2=$items.length;j<length2;j++){var $collapse=$items[j];$collapse.querySelector(".accordion-header").addEventListener("click",function(event){if(this.parentNode.classList.contains("open")){this.parentNode.classList.remove("open")}else{for(var j=0,length2=$items.length;j<length2;j++){var $collapse2=$items[j];$collapse2.classList.remove("open")}
this.parentNode.classList.add("open")}})}}}
function openWidget(){var $menu=document.querySelector(".footer__bottom.info-cmp i");var $footer__widget=document.querySelector(".footer__widget");$menu.addEventListener("click",function(){$footer__widget.classList.add("active")});window.addEventListener("click",function(e){if(!document.querySelector(".footer__widget").contains(e.target)&&!document.querySelector(".footer__bottom.info-cmp").contains(e.target)&&document.querySelector(".footer__widget").classList.contains("active")){$footer__widget.classList.remove("active")}})}
function init(){fixed();modal();visible();openMenu();openMission();accordion();openWidget()}
document.addEventListener("DOMContentLoaded",init,!1);


